// ParticleBackground.js
import React from 'react';
import Particles from "react-tsparticles";

function ParticleBackground() {
  return (
    <Particles
      id="tsparticles"
      options={{
        background: {
          color: { value: "#1e1e1e" },
        },
        fpsLimit: 60,
        particles: {
          color: { value: "#ffffff" },
          links: {
            color: "#ffffff",
            distance: 150,
            enable: true,
            opacity: 0.5,
            width: 1,
          },
          move: {
            direction: "none",
            enable: true,
            outMode: "bounce",
            random: false,
            speed: 2,
            straight: false,
          },
          number: { density: { enable: true, area: 800 }, value: 80 },
          opacity: { value: 0.5 },
          shape: { type: "circle" },
          size: { random: true, value: 5 },
        },
        detectRetina: true,
        interactivity: {
          events: {
            onHover: { enable: true, mode: "repulse" },
            onClick: { enable: true, mode: "push" },
            resize: true,
          },
          modes: {
            push: { quantity: 4 },
            repulse: { distance: 100, duration: 0.4 },
          },
        },
      }}
    />
  );
}

export default ParticleBackground;
